INSERT INTO `job_postings` (`id`, `title`, `department`, `location`, `job_type`, `status`, `posted_date`, `deadline`, `description`, `requirements`, `applicant_count`, `created_by`, `created_at`, `updated_at`) VALUES
(2, 'Instructional Designer', 'Sales', 'Baner, pune', 'Full-time', 'Active', '2025-09-30', '2025-10-04', 'Description of this job, likes and dislikes', '[\"Requirement 1\", \"Requirement 2\", \"Requirement 3\", \"Requirement 4\"]', 0, 3, '2025-09-30 13:24:30', '2025-09-30 13:24:30'),
(3, 'International sales', 'Sales', 'Baner, Pune', 'Full-time', 'Active', '2025-10-06', '2025-10-08', 'We are seeking a confident and fluent International Sales Executive to join our growing team. The ideal candidate should have a strong understanding of the IT and eLearning industry, and excellent command of the English language (both verbal and written). This role involves international client outreach, cold calling, meeting setup, and ongoing client engagement across global markets.', '[\"Conduct cold calls, emails, and LinkedIn outreach to generate leads from international markets (US, UK, Middle East, APAC).\", \"Set up client meetings, demos, and follow-up discussions with professionalism and clarity.\", \"Engage with clients fluently in English—both in speaking and writing.\", \"Present solutions and capabilities effectively during virtual meetings and calls.\", \"Coordinate with internal teams (presales, tech, and content) to develop customized proposals and solutions.\", \"Manage CRM entries and maintain accurate records of leads, interactions, and deal stages.\", \"Support the entire sales lifecycle—from lead generation to closure—ensuring a smooth handover to the delivery team.\", \"Meet monthly and quarterly targets while maintaining high-quality client communication.\", \"Required Skills and Experience:\", \"Bachelor’s degree in Business, Marketing, IT, or a related field.\", \"2–4 years of experience in international sales or business development, preferably in IT/eLearning.\", \"Excellent command of English (verbal and written) is mandatory.\", \"Strong interpersonal and communication skills with the ability to build rapport across cultures and time zones.\", \"Proven experience in client engagement, cold calling, and setting up business meetings.\", \"Familiarity with CRM tools and digital outreach platforms like LinkedIn Sales Navigator.\", \"Ability to understand technical solutions and communicate them in a simplified manner to clients.\"]', 0, 6, '2025-10-06 11:49:33', '2025-10-06 11:49:51'),
(4, 'E-Learning Developer', 'Design', 'Baner, Pune', 'Full-time', 'Active', '2025-10-09', '2027-01-23', 'Responsibilities:\n\nDesign and develop interactive eLearning modules and courses using authoring tools such as Articulate Storyline, Adobe Captivate, or similar software.\nCollaborate with instructional designers, graphic designers, and subject matter experts to translate learning objectives into engaging and interactive learning experiences.\nIncorporate multimedia elements, such as audio, video, and animations, to enhance the learning content and engage learners.\nEnsure eLearning content is accessible, responsive, and compatible with various learning management systems (LMS) and devices.\nTest and troubleshoot eLearning modules to identify and resolve technical issues and ensure optimal performance.', '[\"Requirements:\", \"3-6 years of experience in eLearning development field.\", \"Proficiency in eLearning authoring tools such as Articulate Storyline, Adobe Captivate, or similar software.\", \"Strong understanding of instructional design principles and adult learning theories.\", \"Experience with multimedia development, including audio and video editing.\", \"Knowledge of SCORM and other eLearning standards.\", \"Excellent problem-solving and troubleshooting skills.\", \"Effective communication and collaboration skills.\"]', 0, 6, '2025-10-09 10:31:50', '2025-10-23 13:51:42'),
(5, 'HR Executive & Operations', 'HR', 'Baner, Pune', 'Full-time', 'Active', '2025-10-22', '2027-01-08', 'We are looking for a go-getter HR Executive & Operations professional who is self-driven, energetic, and eager to take ownership. The ideal candidate should have excellent communication skills, the ability to manage multiple tasks simultaneously, and a strong sense of responsibility in handling HR and operational activities.', '[\"Drive end-to-end recruitment and onboarding with confidence and ownership.\", \"Manage day-to-day office operations, ensuring smooth functioning.\", \"Handle employee records, payroll support, and compliance requirements.\", \"Coordinate with teams to resolve issues and keep operations on track.\", \"Support company events and employee engagement activities.\", \"What We’re Looking For:\", \"Postgraduate in HR or relevant field.\", \"1–2 years of HR and operations experience.\", \"Excellent communication and interpersonal skills.\", \"Strong multitasking and problem-solving abilities.\", \"A competitive, self-motivated, and proactive attitude.\", \"Tech-savvy with good knowledge of MS Office & HR tools.\", \"Preference for male candidates from nearby locations\"]', 0, 6, '2025-10-22 07:08:26', '2025-10-22 07:08:26'),
(6, 'Intern & Fresher Sales/Marketing', 'Marketing', 'Baner, Pune', 'Internship', 'Active', '2025-10-22', '2027-01-22', 'We’re Hiring Freshers!\n\nWe are looking for enthusiastic freshers for multiple positions, including:\n\nSales\nBusiness Development Executive (BDE)\nInside Sales\nPresales\nMarket Research\nIf you have a strong learning attitude, excellent communication skills, and a go-getter mindset, we’d love to welcome you to our growing team!', '[\"Send your resume to hr@bylinelearning.com\", \"or Share your CV on WhatsApp: 8421142637\", \"Please include the following details:\", \"Specialization / Degree\", \"Current Location\", \"Willingness to work onsite\", \"Notice Period (if applicable)\", \"Growth opportunities available for the right candidates.\", \"Immediate joiners preferred\"]', 0, 6, '2025-10-22 07:12:43', '2025-10-23 13:51:00'),
(7, 'Content Writer', 'Design', 'Baner, Pune', 'Full-time', 'Active', '2025-10-22', '2027-01-01', 'We are looking for a Content Writer who can research, conceptualize, and write clear, engaging, and well-structured content for eLearning courses and educational materials. The ideal candidate should have a flair for a strong grasp of how to simplify complex concepts for learners', '[\"Research and write original, engaging, and age-appropriate content for educational modules, and digital learning materials.\", \"Simplify complex topics into clear, structured, and relatable narratives.\", \"Collaborate with Instructional Designers and Subject Matter Experts to ensure accuracy and learning effectiveness.\", \"Develop content aligned with International English standards, tone, and cultural context.\", \"Adapt content to various formats — stories, lessons, articles, or interactive learning modules.\", \"Edit and proofread drafts to ensure grammatical accuracy, flow, and consistency in tone.\", \"Maintain deadlines and manage multiple projects simultaneously.\", \"Excellent written and verbal communication in English.\", \"Strong research and storytelling ability.\", \"Understanding of instructional or educational writing preferred.\", \"Creativity in presenting topics in a learner-friendly and engaging way.\", \"Masters & Bachelor’s degree in English, Mass Communication, Journalism, Education, or a related field.\", \"1–3 years of experience in content writing, preferably in education & eLearning.\"]', 0, 6, '2025-10-22 07:14:20', '2025-10-22 07:14:48'),
(8, 'Senior - Full Stack Developer', 'Engineering', 'Baner, Pune', 'Full-time', 'Active', '2025-10-22', '2027-01-01', 'We are looking for a passionate and skilled Full Stack Developer with 3 to 6 years of experience to join our dynamic team. The ideal candidate should have hands-on experience with PHP, Java, and Python, and be comfortable working across both front-end and back-end development.', '[\"Design, develop, test, and maintain web applications and APIs using PHP, Java, and Python.\", \"Collaborate with cross-functional teams to define, design, and ship new features.\", \"Work on both front-end and back-end development tasks.\", \"Write clean, scalable, and well-documented code.\", \"Debug and troubleshoot issues across the stack.\", \"Optimize applications for speed, scalability, and security.\", \"Stay up-to-date with the latest industry trends and technologies.\", \"Proficient in: PHP (Laravel or Core PHP), Java (Spring Boot preferred), Python (Django or Flask).\", \"Experience with front-end technologies: HTML, CSS, JavaScript (React or Angular is a plus).\", \"Knowledge of RESTful APIs, databases (MySQL/PostgreSQL), and version control systems like Git.\", \"Basic understanding of DevOps tools, cloud platforms (AWS/GCP), and CI/CD processes is a plus.\", \"Ability to work independently as well as in a team.\", \"Good problem-solving and communication skills.\"]', 0, 6, '2025-10-22 07:17:28', '2025-10-22 07:18:08'),
(9, 'Animator', 'Design', 'Baner, Pune', 'Full-time', 'Active', '2025-10-22', '2027-01-01', 'Create captivating animations and visual effects for eLearning modules, videos, and interactive simulations.\nCollaborate with instructional designers and graphic designers to develop animations that enhance the learning experience and support instructional objectives.\nUse animation software such as Adobe Animate, After Effects, or similar tools to produce high-quality animations.\nEnsure animations are optimized for various delivery platforms and devices.\nWork closely with project managers to meet project deadlines and deliver animations that exceed client expectations.', '[\"2-5 years of animation experience, preferably in the eLearning or entertainment industry.\", \"Proficiency in animation software such as Adobe Animate, After Effects, or similar tools.\", \"Strong understanding of animation principles and techniques.\", \"Creativity and attention to detail.\", \"Excellent communication and collaboration skills.\"]', 0, 6, '2025-10-22 07:20:21', '2025-10-22 07:20:37'),
(10, 'Graphic Designer', 'Design', 'Baner, Pune', 'Full-time', 'Active', '2025-10-22', '2027-01-22', 'Design engaging visual content, including illustrations, infographics, icons, and layouts for eLearning modules, presentations, and digital learning assets.\nCreate and edit graphics, animations, and visual elements aligned with instructional design storyboards and learning content.\nCollaborate with Instructional Designers, SMEs, and the Animation team to produce high-quality learning materials.\nDevelop user-friendly interfaces (UI) and visual elements for eLearning courses that enhance learner engagement.\nEnsure brand consistency by following client-specific branding guidelines across all design outputs.\nEdit and enhance images, videos, and multimedia assets as per project requirements.\nStay updated with the latest design trends and tools to continuously improve visual content quality.\nHandle multiple projects simultaneously while meeting deadlines.\nParticipate in team discussions and brainstorming sessions to contribute creative ideas.', '[\"2 to 5 years of experience as a Graphic Designer, preferably in the eLearning, EdTech, or corporate learning domain.\", \"Proficiency in Adobe Creative Suite (Photoshop, Illustrator, InDesign, After Effects, Premiere Pro).\", \"Strong understanding of visual hierarchy, color theory, and typography.\", \"Experience in creating graphics for eLearning content, digital presentations, social media, and web designs.\", \"Ability to convert complex information into visually engaging graphics.\", \"Basic knowledge of creating 2D animations and motion graphics is a plus.\", \"Strong organizational and time-management skills.\", \"Excellent attention to detail and ability to work independently as well as in a team.\", \"Experience working with international clients is preferred.\", \"Good to Have:\", \"Knowledge of Articulate Storyline, Rise, or other eLearning authoring tools.\", \"Basic understanding of UI/UX design principles.\", \"Experience working on LMS-based content delivery.\"]', 0, 6, '2025-10-22 13:27:18', '2025-10-22 13:27:18'),
(11, 'Business Development Executive', 'Marketing', 'Baner, Pune', 'Full-time', 'Active', '2025-11-01', '2025-11-30', 'We are seeking a confident and fluent International Sales Executive to join our growing team. The ideal candidate should have a strong understanding of the IT and eLearning industry, and excellent command of the English language (both verbal and written). This role involves international client outreach, cold calling, meeting setup, and ongoing client engagement across global markets.\n\nKey Responsibilities:\n\nConduct cold calls, emails, and LinkedIn outreach to generate leads from international markets (US, UK, Middle East, APAC).\nSet up client meetings, demos, and follow-up discussions with professionalism and clarity.\nEngage with clients fluently in English—both in speaking and writing.\nPresent solutions and capabilities effectively during virtual meetings and calls.\nCoordinate with internal teams (presales, tech, and content) to develop customized proposals and solutions.\nManage CRM entries and maintain accurate records of leads, interactions, and deal stages.\nSupport the entire sales lifecycle—from lead generation to closure—ensuring a smooth handover to the delivery team.\nMeet monthly and quarterly targets while maintaining high-quality client communication.', '[]', 0, 6, '2025-11-01 05:56:17', '2025-11-01 05:56:17'),
(12, 'Senior IT', 'Engineering', 'Baner, Pune', 'Full-time', 'Active', '2025-11-01', '2025-11-30', 'This is a critical, hands-on IT leadership role that combines deep expertise in information systems, LMS technology, and information security. You will be responsible for strengthening, optimizing, and scaling Byline’s digital learning ecosystem — including our Learning Management Systems, eLearning platforms, and IT systems — while ensuring compliance, reliability, and data security.\n\nThis role is about taking that foundation to the next level — enhancing performance, building scalable architecture, and implementing best-in-class security and compliance standards across our operations.\n\nYou’ll work closely with leadership and the development team to align technology strategy with business goals, drive innovation, and mentor the IT and LMS teams. This role requires a leader who’s both strategic and hands-on, guiding the team through example — someone who can code, configure, secure, and lead.\n\nKey Responsibilities:\n\nOversee and optimize Byline’s LMS and eLearning technology stack.\nStrengthen IT security, data protection, and compliance processes.\nDesign scalable systems to support content delivery and user growth.\nCollaborate with leadership to align technology initiatives with business strategy.\nLead and mentor a growing tech team, fostering a culture of learning and excellence.\nEvaluate and integrate new technologies to improve system performance and security.\nManage vendor relationships and ensure operational reliability across systems.', '[]', 0, 6, '2025-11-01 11:07:01', '2025-11-01 11:07:01'),
(13, 'Digital Marketing Executive', 'Sales', 'Baner, pune', 'Full-time', 'Active', '2025-12-02', '2029-10-02', 'We are looking for a skilled Digital Marketing Executive with strong experience in SEO, organic marketing, content understanding, and basic website management. The ideal candidate should also have exposure to handling international markets, especially for lead generation and brand visibility.\n\nKey Responsibilities\n\nDevelop and execute effective SEO strategies (on-page, off-page, keyword research, technical SEO).\nWork closely with the content team to ensure SEO-optimized blogs, landing pages, and website copy.\nManage and improve organic visibility in both domestic and international markets.\nConduct competitor analysis and research trends specifically for global audiences.\nMonitor and maintain website performance, structure, and SEO hygiene (coordinate with dev team as needed).\nTrack and analyze website data using Google Analytics, Search Console, and SEO tools.\nAssist in overall digital marketing initiatives like content planning, social presence, and website updates.\nStay updated with SEO algorithm changes and global digital marketing trends.', '[\"1–3 years of experience in SEO and organic marketing.\", \"Experience or exposure in handling international markets.\", \"Strong understanding of content strategy, keyword mapping, and search intent.\", \"Familiarity with CMS platforms like WordPress and basic website management.\", \"Hands-on experience with SEO tools such as Ahrefs, SEMrush, Moz, Ubersuggest, etc.\", \"Strong analytical skills with the ability to generate insights from digital data.\", \"Good communication skills and ability to work collaboratively.\", \"Good to Have\", \"Understanding of social media strategy for global audiences.\", \"Basic HTML/CSS knowledge for minor website updates.\", \"Experience in a service-based or EdTech environment.\"]', 0, 7, '2025-12-02 13:51:53', '2025-12-02 13:51:53'),
(14, 'Visualizer', 'Design', 'Baner, Pune', 'Full-time', 'Active', '2025-12-03', '2029-11-03', 'We are looking for a creative Visualizer (2-6 Years of Experience) who can transform plain text, ideas, and content into visually appealing designs. The ideal candidate must have strong visualization skills, design sense, and the ability to translate information into clear, engaging visual formats.\n\nKey Responsibilities\n\nConvert raw text/content into attractive visual designs.\nCreate layouts, infographics, and visual concepts based on provided content.\nWork closely with Instructional Designers and Content Teams to understand the message and design accordingly.\nMaintain visual consistency, clarity, and branding across all designs.\nDevelop clean, modern, and impactful visuals that simplify complex information.\nEdit and enhance existing designs to improve visual quality.\nDeliver designs within timelines while maintaining high quality.', '[\"Required Skills\", \"Strong ability to visualize text and convert information into engaging designs.\", \"Good understanding of layout, color sense, typography, iconography, and visual hierarchy.\", \"Proficiency in Adobe Tools: Adobe Illustrator / Photoshop/ InDesign.\", \"Creative thinking and attention to detail.\", \"Ability to handle multiple projects simultaneously.\"]', 0, 7, '2025-12-03 14:12:20', '2025-12-03 14:12:20'),
(15, 'Project Coordinator', 'Product', 'Baner, Pune', 'Full-time', 'Active', '2025-12-04', '2028-08-04', 'We are looking for a Project Manager with 2-5 years of experience who can efficiently handle multiple projects and clients, especially international customers. The ideal candidate should have excellent communication skills, be highly organized, and thrive in a fast-paced, dynamic environment. They should be adept at multitasking, problem-solving, and ensuring seamless project execution while maintaining strong client relationships.\n\nKey Responsibilities\n\nManage and oversee multiple projects simultaneously, ensuring timely delivery and high-quality output.\nPlan project timelines, allocate resources, and coordinate with cross-functional teams.\nMonitor project progress, identify risks, and implement proactive solutions.\nEnsure clear communication and alignment between clients, internal teams, and stakeholders.\nMaintain project documentation, reports, and status updates.\nDrive continuous improvement in project processes and delivery efficiency.\nWork in a dynamic, fast-changing environment, adapting to new challenges and business needs.', '[\"2-5 years of experience in project management, preferably in the eLearning, IT, or services industry.\", \"Exceptional communication skills (both verbal and written) to interact effectively with global clients.\", \"Strong ability to multi-task and manage multiple projects efficiently.\", \"Experience working with international clients and handling customer relationships.\", \"Excellent problem-solving and decision-making skills.\", \"Ability to work in a fast-paced and dynamic environment.\", \"Strong analytical, organizational, and leadership skills.\"]', 0, 7, '2025-12-04 13:02:43', '2025-12-04 13:02:43'),
(16, 'Instructional Designer', 'Design', 'Baner, Pune', 'Full-time', 'Active', '2025-12-06', '2030-07-06', 'Key Responsibilities:\n\nDesign and develop engaging eLearning and instructor-led training content.\nAnalyze learning requirements and define clear learning objectives and outcomes.\nCreate detailed storyboards, scripts, and learning outlines for digital courses.\nCollaborate closely with SMEs, visual designers, and developers to ensure learning effectiveness.\nApply instructional design models such as ADDIE, Blooms Taxonomy, and Gagn’s Nine Events.\nReview and evaluate course effectiveness and suggest enhancements.\nEnsure content quality, instructional clarity, and learner engagement across all projects.', '[\"2–6 years of experience in instructional design or eLearning content development.\", \"Sound understanding of instructional design models, adult learning principles, and cognitive learning theories.\", \"Strong visualization and storytelling skills.\", \"Experience working with eLearning authoring tools (Articulate Storyline, Rise, Captivate, etc.).\", \"Excellent written and verbal communication skills.\", \"Ability to manage multiple projects and deadlines.\", \"Qualification:\", \"Bachelor’s or Master’s degree in Instructional Design, Education, Communication, English, or related fields.\", \"Certification in Instructional Design / eLearning will be an added advantage.\", \"Role: Other\", \"Industry Type: E-Learning / EdTech\", \"Department: Other\", \"Employment Type: Full Time, Permanent\", \"Role Category: Other\", \"Education\", \"PG: Any Postgraduate\"]', 0, 7, '2025-12-06 08:56:20', '2025-12-06 08:56:29'),
(17, 'Instructional Content Writer', 'Design', 'Baner', 'Full-time', 'Active', '2025-12-06', '2029-10-06', 'Job description\nWe’re hiring an Instructional Content Writer to create engaging learning content, scripts,& assessments. Strong writing, attention to detail, and passion for crafting learning experiences for all age groups. eLearning/content dev experience preferred\n\nRequired Candidate profile\n\nStrong command of English, content structuring, and storyboarding. Skilled at simplifying complex topics with flexible application of pedagogy and andragogy for diverse learning needs.\n\nPerks and benefits\n\nCreative workspace growth& learning opportunities.\nRole: Instructional Designer\nIndustry Type: E-Learning / EdTech\nDepartment: Content, Editorial & Journalism\nEmployment Type: Full Time, Permanent\nRole Category: Content Management (Print / Online / Electronic)\nEducation\nPG: Any Postgraduate', '[]', 0, 7, '2025-12-06 11:41:20', '2025-12-06 11:41:20'),
(18, 'Intern/Fresher', 'Marketing', 'Baner', 'Full-time', 'Active', '2026-01-21', '2037-05-05', 'We’re Hiring Freshers!\n\nWe are looking for enthusiastic freshers for multiple positions, including:\n\nSales\nBusiness Development Executive (BDE)\nInside Sales\nPresales\nMarket Research\nIf you have a strong learning attitude, excellent communication skills, and a go-getter mindset, we’d love to welcome you to our growing team!\n\nLocation: Baner, Pune (Onsite)\nWork Mode: Full-time, 5 days a week with alternate Saturday Working\nEligibility: Fresh graduates from any stream with good communication and interest in business roles\n\nHow to Apply:\nSend your resume to hr@bylinelearning.com\nor Share your CV on WhatsApp: 8421142637\n\nPlease include the following details:\n\nSpecialization / Degree\nCurrent Location\nWillingness to work onsite\nNotice Period (if applicable)\nGrowth opportunities available for the right candidates.\nImmediate joiners preferred\n\nJob Type: Full-time', '[\"Ability to commute/relocate:\", \"Pune, Maharashtra: Reliably commute or planning to relocate before starting work (Preferred)\", \"Education:\", \"Master\'s (Preferred)\", \"Language:\", \"English (Required)\", \"Location:\", \"Pune, Maharashtra (Preferred)\", \"Work Location: In person\"]', 0, 7, '2026-01-21 07:13:15', '2026-01-21 07:13:15'),
(19, 'Full Stack Developer', 'Engineering', 'Baner', 'Full-time', 'Active', '2026-02-02', '2035-12-02', 'We are looking for a Full Stack Developer with strong experience in both frontend and backend development, preferably from the eLearning or LMS industry. The ideal candidate understands multi-user systems, data confidentiality, and secure application architecture, similar to environments seen in fintech or data-sensitive platforms.\n\nThis role requires someone who can build, secure, and scale applications, and think about security, performance, and user access from every angle.\n\nKey Responsibilities:\n\nDesign, develop, and maintain secure web applications for LMS and eLearning platforms\nHandle multi-user access, role-based permissions, and data confidentiality\nBuild and manage frontend and backend components of applications\nIntegrate eLearning modules, assessments, reporting, and user dashboards\nWork with AWS / cloud infrastructure for deployment, scalability, and security\nEnsure application security, data protection, and system reliability\nCollaborate closely with content, LMS, and product teams\nTechnical Expertise:\n\nStrong experience in Node.js / PHP / React (any one or combination)\n5–9 years of hands-on full stack development experience\nExperience with LMS platforms and eLearning workflows\nKnowledge of AWS services, databases, APIs, and authentication systems\nExperience building secure, data-driven applications\nUnderstanding of encryption, access control, and secure coding practices\nPreferred Background:\n\nExperience in eLearning, LMS, EdTech, or fintech-like secure systems\nStrong understanding of handling multiple users and isolated data environments\nAbility to think from both development and security perspectives\nProblem-solver with attention to detail and system design', '[]', 0, 7, '2026-02-02 07:26:20', '2026-02-02 07:26:20'),
(20, 'LinkedIn Profiles ID', 'Design', 'Baner', 'Full-time', 'Active', '2026-02-06', '2035-03-12', 'Key Responsibilities:\n\nDesign and develop engaging eLearning and instructor-led training content.\nAnalyze learning requirements and define clear learning objectives and outcomes.\nCreate detailed storyboards, scripts, and learning outlines for digital courses.\nCollaborate closely with SMEs, visual designers, and developers to ensure learning effectiveness.\nApply instructional design models such as ADDIE, Blooms Taxonomy, and Gagn’s Nine Events.\nReview and evaluate course effectiveness and suggest enhancements.\nEnsure content quality, instructional clarity, and learner engagement across all projects.\n\nRequirements\n2–6 years of experience in instructional design or eLearning content development.\nSound understanding of instructional design models, adult learning principles, and cognitive learning theories.\nStrong visualization and storytelling skills.\nExperience working with eLearning authoring tools (Articulate Storyline, Rise, Captivate, etc.).\nExcellent written and verbal communication skills.\nAbility to manage multiple projects and deadlines.\nQualification:\nBachelor’s or Master’s degree in Instructional Design, Education, Communication, English, or related fields.\nCertification in Instructional Design / eLearning will be an added advantage.\nRole: Other\nIndustry Type: E-Learning / EdTech\nDepartment: Other\nEmployment Type: Full Time, Permanent\nRole Category: Other\nEducation\nPG: Any Postgraduate', '[]', 0, 7, '2026-02-06 06:42:17', '2026-02-06 06:43:19'),
(21, 'LinkedIn Profile Sales', 'Sales', 'Baner', 'Full-time', 'Active', '2026-02-06', '2035-03-12', 'Job Description\nWe are seeking a confident and fluent International Sales Executive to join our growing team. The ideal candidate should have a strong understanding of the IT and eLearning industry, and excellent command of the English language (both verbal and written). This role involves international client outreach, cold calling, meeting setup, and ongoing client engagement across global markets.\n\nKey Responsibilities:\n\nConduct cold calls, emails, and LinkedIn outreach to generate leads from international markets (US, UK, Middle East, APAC).\nSet up client meetings, demos, and follow-up discussions with professionalism and clarity.\nEngage with clients fluently in English—both in speaking and writing.\nPresent solutions and capabilities effectively during virtual meetings and calls.\nCoordinate with internal teams (presales, tech, and content) to develop customized proposals and solutions.\nManage CRM entries and maintain accurate records of leads, interactions, and deal stages.\nSupport the entire sales lifecycle—from lead generation to closure—ensuring a smooth handover to the delivery team.\nMeet monthly and quarterly targets while maintaining high-quality client communication.', '[]', 0, 7, '2026-02-06 06:45:37', '2026-02-06 06:45:37'),
(22, 'LinkedIn Profiles IT', 'Engineering', 'Baner', 'Full-time', 'Active', '2026-02-06', '2035-03-12', 'Job Description\nWe are looking for a Full Stack Developer with strong experience in both frontend and backend development, preferably from the eLearning or LMS industry. The ideal candidate understands multi-user systems, data confidentiality, and secure application architecture, similar to environments seen in fintech or data-sensitive platforms.\n\nThis role requires someone who can build, secure, and scale applications, and think about security, performance, and user access from every angle.\n\nKey Responsibilities:\n\nDesign, develop, and maintain secure web applications for LMS and eLearning platforms\nHandle multi-user access, role-based permissions, and data confidentiality\nBuild and manage frontend and backend components of applications\nIntegrate eLearning modules, assessments, reporting, and user dashboards\nWork with AWS / cloud infrastructure for deployment, scalability, and security\nEnsure application security, data protection, and system reliability\nCollaborate closely with content, LMS, and product teams\nTechnical Expertise:\n\nStrong experience in Node.js / PHP / React (any one or combination)\n5–9 years of hands-on full stack development experience\nExperience with LMS platforms and eLearning workflows\nKnowledge of AWS services, databases, APIs, and authentication systems\nExperience building secure, data-driven applications\nUnderstanding of encryption, access control, and secure coding practices\nPreferred Background:\n\nExperience in eLearning, LMS, EdTech, or fintech-like secure systems\nStrong understanding of handling multiple users and isolated data environments\nAbility to think from both development and security perspectives\nProblem-solver with attention to detail and system design', '[]', 0, 7, '2026-02-06 06:47:52', '2026-02-06 06:47:52'),
(23, 'Animator', 'Design', 'Baner', 'Full-time', 'Active', '2026-02-10', '2035-03-01', 'Job description\nResponsibilities:\nCreate captivating animations and visual effects for eLearning modules, videos, and interactive simulations.\nCollaborate with instructional designers and graphic designers to develop animations that enhance the learning experience and support instructional objectives.\nUse animation software such as Adobe Animate, After Effects, or similar tools to produce high-quality animations.\nEnsure animations are optimized for various delivery platforms and devices.\nWork closely with project managers to meet project deadlines and deliver animations that exceed client expectations.\nRequirements:\n\n1-3 years of animation experience, preferably in the eLearning or entertainment industry.\nProficiency in animation software such as Adobe Animate, After Effects, or similar tools.\nStrong understanding of animation principles and techniques.\nCreativity and attention to detail.\nExcellent communication and collaboration skills.\nBasic to intermediate knowledge of 3D animation\nEmployment Type: Full-time, work-from-office\n\nImmediate joining preferred\n\nJob Type: Full-time\n\nWork Location: In person', '[]', 0, 7, '2026-02-10 10:18:13', '2026-02-10 10:18:13'),
(24, 'Graphic Designer', 'Design', 'Baner', 'Full-time', 'Active', '2026-02-10', '2035-03-11', 'Job Description:\n\nResponsibilities:\n\nCreate visually appealing graphics and illustrations for various eLearning projects, including corporate training modules and educational courses.\nCollaborate with the instructional design team to ensure graphics align with instructional objectives and enhance learning outcomes.\nUse Adobe Creative Suite (Photoshop, Illustrator, InDesign) to design high-quality graphics, icons, and animations.\nWork closely with project managers to meet project deadlines and deliver exceptional results.\nRequirements:\n\n2-5 years of graphic design experience, preferably in the eLearning industry.\nProficiency in Adobe Creative Suite, particularly Photoshop, Illustrator, and InDesign.\nStrong creative and conceptual skills with a keen eye for detail.\nExcellent communication and collaboration skills.\nAbility to work effectively in a fast-paced environment and manage multiple projects simultaneously.', '[]', 0, 7, '2026-02-10 12:34:26', '2026-02-10 12:34:26'),
(25, 'Digital Marketing Executive', 'Marketing', 'Baner', 'Full-time', 'Active', '2026-02-11', '2035-03-11', 'Job description:\n\nWe are looking for a skilled Digital Marketing Executive with strong experience in SEO, organic marketing, content understanding, and basic website management. The ideal candidate should also have exposure to handling international markets, especially for lead generation and brand visibility.\n\nKey Responsibilities\n\nDevelop and execute effective SEO strategies (on-page, off-page, keyword research, technical SEO).\nWork closely with the content team to ensure SEO-optimized blogs, landing pages, and website copy.\nManage and improve organic visibility in both domestic and international markets.\nConduct competitor analysis and research trends specifically for global audiences.\nMonitor and maintain website performance, structure, and SEO hygiene (coordinate with dev team as needed).\nTrack and analyze website data using Google Analytics, Search Console, and SEO tools.\nAssist in overall digital marketing initiatives like content planning, social presence, and website updates.\nStay updated with SEO algorithm changes and global digital marketing trends.\nRequired Skills & Qualifications\n\n1–3 years of experience in SEO and organic marketing.\nExperience or exposure in handling international markets.\nStrong understanding of content strategy, keyword mapping, and search intent.\nFamiliarity with CMS platforms like WordPress and basic website management.\nHands-on experience with SEO tools such as Arefs, SEMrush, Moz, Uber suggest, etc.\nStrong analytical skills with the ability to generate insights from digital data.\nGood communication skills and ability to work collaboratively.\nGood to Have\nUnderstanding of social media strategy for global audiences.\nBasic HTML/CSS knowledge for minor website updates.\nExperience in a service-based or EdTech environment.', '[]', 0, 7, '2026-02-11 11:00:18', '2026-02-11 11:00:18'),
(26, 'Project Manager/Coordinator', 'Sales', 'Baner', 'Full-time', 'Active', '2026-02-12', '2035-03-01', 'Job description:\n\nWe are looking for a Project Manager with 2-5 years of experience who can efficiently handle multiple projects and clients, especially international customers. The ideal candidate should have excellent communication skills, be highly organized, and thrive in a fast-paced, dynamic environment. They should be adept at multitasking, problem-solving, and ensuring seamless project execution while maintaining strong client relationships.\n\nKey Responsibilities\n\nManage and oversee multiple projects simultaneously, ensuring timely delivery and high-quality output.\nPlan project timelines, allocate resources, and coordinate with cross-functional teams.\nMonitor project progress, identify risks, and implement proactive solutions.\nEnsure clear communication and alignment between clients, internal teams, and stakeholders.\nMaintain project documentation, reports, and status updates.\nDrive continuous improvement in project processes and delivery efficiency.\nWork in a dynamic, fast-changing environment, adapting to new challenges and business needs.\nRequired Skills & Qualifications\n\n2-5 years of experience in project management, preferably in the eLearning, IT, or services industry.\nExceptional communication skills (both verbal and written) to interact effectively with global clients.\nStrong ability to multi-task and manage multiple projects efficiently.\nExperience working with international clients and handling customer relationships.\nExcellent problem-solving and decision-making skills.\nAbility to work in a fast-paced and dynamic environment.\nStrong analytical, organizational, and leadership skills.', '[]', 0, 7, '2026-02-12 11:01:54', '2026-02-12 11:01:54');
